import { useSearchParams } from "react-router-dom";
import { Link2, MessageSquare, Sparkles, Settings, Receipt, FileSignature } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";

// Tab content
import CreviaLink from "./CreviaLink";
import SmartInvoicesTab from "@/components/studio/SmartInvoicesTab";
import ContractsTab from "@/components/studio/ContractsTab";
import StudioSettingsTab from "@/components/studio/StudioSettingsTab";
import StudioWorkspacesHub from "@/components/studio/workspaces/StudioWorkspacesHub";

const CreviaStudio = () => {
  const [searchParams, setSearchParams] = useSearchParams();

  const activeTab = searchParams.get("tab") || "link";
  const activeLinkSection = searchParams.get("section") || "profile";
  const activeWorkspace = searchParams.get("workspace") || undefined;
  const activeRoomId = searchParams.get("roomId") || undefined;

  // Strict order: Link → Workspace → Invoice → Contracts → Settings
  const studioTabs = [
    { id: "link",      label: "Crevia Link", icon: Link2 },
    { id: "chat",      label: "Workspace",   icon: MessageSquare },
    { id: "invoices",  label: "Invoice",     icon: Receipt },
    { id: "contracts", label: "Contracts",   icon: FileSignature },
    { id: "settings",  label: "Settings",    icon: Settings },
  ];

  const linkSections = [
    { id: "profile",    label: "Profile" },
    { id: "buttons",    label: "Buttons" },
    { id: "appearance", label: "Appearance" },
    { id: "settings",   label: "Settings" },
    { id: "analytics",  label: "Analytics" },
  ];

  const handleTabChange = (tabId: string) => {
    setSearchParams({ tab: tabId });
  };

  const handleLinkSectionChange = (sectionId: string) => {
    setSearchParams({ tab: "link", section: sectionId });
  };

  const isChatTab = activeTab === "chat";

  return (
    <div className={cn(
      "bg-background",
      isChatTab
        ? "h-[calc(100vh-128px)] md:h-[calc(100vh-64px)] flex flex-col overflow-hidden"
        : "min-h-screen overflow-x-hidden"
    )}>
      {/* Studio Header */}
      <div className={cn(
        "border-b border-border bg-background z-30 flex-shrink-0",
        !isChatTab && "md:sticky md:top-0"
      )}>
        <div className="mx-auto w-full max-w-7xl px-4 py-3 md:px-6 md:py-4">
          <div className="flex items-center gap-3 mb-3 md:mb-4">
            <div className="p-1.5 md:p-2 rounded-xl bg-bronze/10">
              <Sparkles className="h-4 w-4 md:h-5 md:w-5 text-bronze" />
            </div>
            <div>
              <h1 className="font-vollkorn text-xl md:text-2xl font-semibold text-foreground">
                Crevia Studio
              </h1>
              <p className="text-sm md:text-base text-muted-foreground">
                Your creative business toolkit
              </p>
            </div>
          </div>

          {/* Tabs — strict order enforced by studioTabs array */}
          <ScrollArea className="w-full">
            <div className="flex items-center gap-1 pb-1 -mb-px">
              {studioTabs.map((tab) => {
                const Icon = tab.icon;
                const isActive = activeTab === tab.id;
                return (
                  <button
                    key={tab.id}
                    onClick={() => handleTabChange(tab.id)}
                    title={tab.label}
                    className={cn(
                      "flex items-center gap-1.5 px-3 py-2.5 rounded-t-lg font-poppins text-sm font-medium whitespace-nowrap transition-all duration-300 min-w-[44px] justify-center",
                      isActive
                        ? "bg-bronze/10 text-bronze border-b-2 border-bronze"
                        : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
                    )}
                  >
                    <Icon className="h-4 w-4 flex-shrink-0" />
                    <span className="hidden sm:inline">{tab.label}</span>
                  </button>
                );
              })}
            </div>
            <ScrollBar orientation="horizontal" className="h-1.5" />
          </ScrollArea>

          {/* Link sub-sections (mobile only) — segmented control */}
          {activeTab === "link" && (
            <div className="md:hidden mt-2 border-t border-border/40 pt-2">
              {/* Row 1: Profile · Buttons · Appearance */}
              <div className="flex gap-1 p-1 bg-muted/60 rounded-xl mb-1">
                {linkSections.slice(0, 3).map((section) => (
                  <button
                    key={section.id}
                    type="button"
                    onClick={() => handleLinkSectionChange(section.id)}
                    className={cn(
                      "flex-1 py-1.5 rounded-lg text-[11px] font-semibold text-center transition-all duration-200 active:scale-95",
                      activeLinkSection === section.id
                        ? "bg-background text-foreground shadow-sm"
                        : "text-muted-foreground"
                    )}
                  >
                    {section.label}
                  </button>
                ))}
              </div>
              {/* Row 2: Settings · Analytics */}
              <div className="flex gap-1 p-1 bg-muted/60 rounded-xl">
                {linkSections.slice(3).map((section) => (
                  <button
                    key={section.id}
                    type="button"
                    onClick={() => handleLinkSectionChange(section.id)}
                    className={cn(
                      "flex-1 py-1.5 rounded-lg text-[11px] font-semibold text-center transition-all duration-200 active:scale-95",
                      activeLinkSection === section.id
                        ? "bg-background text-foreground shadow-sm"
                        : "text-muted-foreground"
                    )}
                  >
                    {section.label}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Tab Content */}
      {isChatTab ? (
        <div className="flex-1 min-h-0 overflow-hidden">
          <StudioWorkspacesHub initialRoomId={activeRoomId} />
        </div>
      ) : (
        <div className="flex-1 min-w-0 overflow-x-hidden">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -6 }}
              transition={{ duration: 0.3, ease: [0.25, 0.46, 0.45, 0.94] }}
            >
              {activeTab === "link"      && <CreviaLink isEmbedded />}
              {activeTab === "invoices"  && <SmartInvoicesTab workspaceId={activeWorkspace} />}
              {activeTab === "contracts" && <ContractsTab workspaceId={activeWorkspace} />}
              {activeTab === "settings"  && <StudioSettingsTab />}
            </motion.div>
          </AnimatePresence>
        </div>
      )}
    </div>
  );
};

export default CreviaStudio;

import { useState, useEffect, lazy, Suspense } from "react";

import { Toaster } from "@/components/ui/toaster";
import { Toaster as Sonner } from "@/components/ui/sonner";
import { TooltipProvider } from "@/components/ui/tooltip";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { BrowserRouter, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { ThemeProvider } from "@/components/ThemeProvider";
import { LanguageProvider } from "@/i18n/LanguageContext";
import { supabase } from "@/integrations/supabase/client";
import { useInitializeE2EE } from "@/hooks/use-initialize-e2ee";
import { RecoveryPasswordModal } from "@/components/auth/RecoveryPasswordModal";
import { SetRecoveryPasswordDialog } from "@/components/auth/SetRecoveryPasswordDialog";
import ScrollToTop from "./components/ScrollToTop";
import { ErrorBoundary } from "./components/ErrorBoundary";
import { CookieConsent } from "./components/CookieConsent";
import AppLayout from "./components/navigation/AppLayout";
import PublicPageWrapper from "./components/PublicPageWrapper";
import ProtectedRoute from "./components/auth/ProtectedRoute";

// Eagerly loaded — tiny or always needed immediately
import Home from "./pages/Home";
import Auth from "./pages/Auth";
import AuthCallback from "./pages/AuthCallback";
import NotFound from "./pages/NotFound";
import MFAVerify from "./components/auth/MFAVerify";

// Lazy-loaded — split into separate chunks to reduce initial bundle
const ResetPassword    = lazy(() => import("./pages/ResetPassword"));
const Kira             = lazy(() => import("./pages/Kira"));
const CreviaLink       = lazy(() => import("./pages/CreviaLink"));
const CreviaStudio     = lazy(() => import("./pages/CreviaStudio"));
const CreviaInvoice    = lazy(() => import("./pages/CreviaInvoice"));
const CreviaContracts  = lazy(() => import("./pages/CreviaContracts"));
const WorkspacesList   = lazy(() => import("./pages/WorkspacesList"));
const WorkspacePage    = lazy(() => import("./pages/WorkspacePage"));
const WorkspaceInvitePage = lazy(() => import("./pages/WorkspaceInvitePage"));
const PublicProfile    = lazy(() => import("./pages/PublicProfile"));
const ReceivedDocuments = lazy(() => import("./pages/ReceivedDocuments"));
const PaymentsBilling  = lazy(() => import("./pages/profile/PaymentsBilling"));
const Notifications    = lazy(() => import("./pages/profile/Notifications"));
const Verification     = lazy(() => import("./pages/profile/Verification"));
const Settings         = lazy(() => import("./pages/profile/Settings"));
const Help             = lazy(() => import("./pages/profile/Help"));
const Feedback         = lazy(() => import("./pages/profile/Feedback"));
const Admin            = lazy(() => import("./pages/Admin"));
const Pricing          = lazy(() => import("./pages/Pricing"));
const About            = lazy(() => import("./pages/About"));
const PrivacyPolicy    = lazy(() => import("./pages/PrivacyPolicy"));
const TermsOfService   = lazy(() => import("./pages/TermsOfService"));
const CookiePolicy     = lazy(() => import("./pages/CookiePolicy"));

const PageLoader = () => (
  <div className="min-h-screen flex items-center justify-center bg-background">
    <div className="w-8 h-8 rounded-full border-2 border-bronze border-t-transparent animate-spin" />
  </div>
);

const MaintenancePage = () => (
  <div className="min-h-screen bg-background flex flex-col items-center justify-center px-4 text-center">
    <img src="/crevia-logo.png" alt="Crevia" className="w-14 h-14 rounded-full ring-1 ring-border mb-8" />
    <h1 className="font-vollkorn text-3xl md:text-4xl font-bold mb-3">Down for maintenance</h1>
    <p className="text-muted-foreground text-sm max-w-sm leading-relaxed">
      We're making some improvements to Crevia. We'll be back shortly — thank you for your patience.
    </p>
  </div>
);

const queryClient = new QueryClient();

// AppContent lives inside BrowserRouter so routing hooks are available.
// useInitializeE2EE is called HERE — at the very top of this component,
// before any conditional returns — so React's rules of hooks are never violated.
function AppContent() {
  const [userId, setUserId] = useState("");
  const [maintenance, setMaintenance] = useState(false);
  const location = useLocation();

  // MUST be called before any early returns.
  // Receives "" until the auth state resolves, then fires the full init flow.
  const {
    error: e2eeError,
    needsRecoveryPassword,
    needsMigration,
    provideRecoveryPassword,
    clearMigrationFlag,
  } = useInitializeE2EE(userId);

  const [migrationDialogOpen, setMigrationDialogOpen] = useState(false);

  // Open the migration dialog as soon as the flag is raised, but only once per session.
  useEffect(() => {
    if (needsMigration) setMigrationDialogOpen(true);
  }, [needsMigration]);

  useEffect(() => {
    // onAuthStateChange fires immediately with the current session
    // (INITIAL_SESSION event) AND fires again on every sign-in / sign-out.
    // This is more reliable than getSession() which can return null on the
    // first tick in OAuth / server-redirect flows.
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setUserId(session?.user?.id ?? "");
    });

    return () => subscription.unsubscribe();
  }, []);

  // Background maintenance check — never blocks render
  useEffect(() => {
    supabase.from("app_settings" as any)
      .select("value")
      .eq("key", "maintenance_mode")
      .single()
      .then(({ data }) => {
        if ((data as any)?.value === "true") setMaintenance(true);
      });
  }, []);

  // Admin path always bypasses maintenance so the toggle can be turned off
  if (maintenance && !location.pathname.startsWith("/admin")) return <MaintenancePage />;

  return (
    <>
      <ScrollToTop />
      <CookieConsent />

      {/* Non-dismissible: shown on a new device when a v2 backup exists */}
      <RecoveryPasswordModal
        open={needsRecoveryPassword}
        error={e2eeError}
        onSubmit={provideRecoveryPassword}
      />

      {/* Dismissible: nudges v1 users and new users to set a recovery password */}
      <SetRecoveryPasswordDialog
