          <Route path="/cookie-policy" element={<AppLayout><CookiePolicy /></AppLayout>} />
          <Route path="/user-type-selection" element={<Navigate to="/auth" replace />} />
          <Route path="/signup/creator" element={<Navigate to="/auth?mode=signup" replace />} />
