cat << 'ENDSQL'
-- ═══════════════════════════════════════════════════════════════
-- CREVIA ADMIN — FULL MIGRATION (run in Supabase SQL Editor)
-- ═══════════════════════════════════════════════════════════════

-- ── 1. User suspension ──────────────────────────────────────────
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS is_suspended boolean NOT NULL DEFAULT false;

-- DB-level enforcement: suspended users cannot insert/update invoices or contracts
-- (even via direct API calls)
CREATE OR REPLACE FUNCTION public.check_not_suspended()
RETURNS boolean LANGUAGE sql SECURITY DEFINER STABLE AS $$
  SELECT NOT COALESCE(
    (SELECT is_suspended FROM public.profiles WHERE id = auth.uid()),
    false
  )
$$;

-- ── 2. Soft delete for documents ───────────────────────────────
ALTER TABLE invoices  ADD COLUMN IF NOT EXISTS deleted_at timestamptz DEFAULT NULL;
ALTER TABLE contracts ADD COLUMN IF NOT EXISTS deleted_at timestamptz DEFAULT NULL;

CREATE INDEX IF NOT EXISTS idx_invoices_active  ON invoices(user_id)  WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_contracts_active ON contracts(user_id) WHERE deleted_at IS NULL;

-- ── 3. Invoice templates ────────────────────────────────────────
CREATE TABLE IF NOT EXISTS invoice_templates (
  id               uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_by       uuid        REFERENCES profiles(id) ON DELETE SET NULL,
  name             text        NOT NULL,
  description      text,
  default_currency text        NOT NULL DEFAULT 'KES',
  default_notes    text,
  default_terms    text,
  line_items       jsonb       NOT NULL DEFAULT '[]',
  is_global        boolean     NOT NULL DEFAULT false,
  created_at       timestamptz NOT NULL DEFAULT now(),
  updated_at       timestamptz NOT NULL DEFAULT now()
);
ALTER TABLE invoice_templates ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "it_select" ON invoice_templates;
DROP POLICY IF EXISTS "it_insert" ON invoice_templates;
DROP POLICY IF EXISTS "it_update" ON invoice_templates;
DROP POLICY IF EXISTS "it_delete" ON invoice_templates;
CREATE POLICY "it_select" ON invoice_templates FOR SELECT USING (
  created_by = auth.uid() OR is_global = true
  OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true)
);
CREATE POLICY "it_insert" ON invoice_templates FOR INSERT WITH CHECK (
  created_by = auth.uid()
  OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true)
);
CREATE POLICY "it_update" ON invoice_templates FOR UPDATE USING (
  created_by = auth.uid()
  OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true)
);
CREATE POLICY "it_delete" ON invoice_templates FOR DELETE USING (
  created_by = auth.uid()
  OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true)
);

-- ── 4. Contract templates ───────────────────────────────────────
CREATE TABLE IF NOT EXISTS contract_templates (
  id             uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_by     uuid        REFERENCES profiles(id) ON DELETE SET NULL,
  name           text        NOT NULL,
  description    text,
  contract_type  text,
  body_template  text,
  default_terms  text,
  is_global      boolean     NOT NULL DEFAULT false,
  created_at     timestamptz NOT NULL DEFAULT now(),
  updated_at     timestamptz NOT NULL DEFAULT now()
);
ALTER TABLE contract_templates ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "ct_select" ON contract_templates;
DROP POLICY IF EXISTS "ct_insert" ON contract_templates;
DROP POLICY IF EXISTS "ct_update" ON contract_templates;
DROP POLICY IF EXISTS "ct_delete" ON contract_templates;
CREATE POLICY "ct_select" ON contract_templates FOR SELECT USING (
  created_by = auth.uid() OR is_global = true
  OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true)
);
CREATE POLICY "ct_insert" ON contract_templates FOR INSERT WITH CHECK (
  created_by = auth.uid()
  OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true)
);
CREATE POLICY "ct_update" ON contract_templates FOR UPDATE USING (
  created_by = auth.uid()
  OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true)
);
CREATE POLICY "ct_delete" ON contract_templates FOR DELETE USING (
  created_by = auth.uid()
  OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true)
);

-- ── 5. Add category to support_tickets ─────────────────────────
ALTER TABLE support_tickets ADD COLUMN IF NOT EXISTS category text NOT NULL DEFAULT 'question';
DO $$ BEGIN
  BEGIN
    ALTER TABLE support_tickets
      ADD CONSTRAINT support_tickets_category_check
      CHECK (category IN ('bug', 'feature', 'question', 'billing'));
  EXCEPTION WHEN duplicate_object THEN NULL;
  END;
END $$;

-- ── 6. App settings — pricing + SMTP ──────────────────────────
INSERT INTO app_settings (key, value) VALUES
  ('plan_pro_price',        '1500'),
  ('plan_enterprise_price', '5000'),
  ('smtp_from',             'noreply@crevia.app'),
  ('smtp_reply_to',         '')
ON CONFLICT (key) DO NOTHING;

-- ── 7. Admin API keys ───────────────────────────────────────────
CREATE TABLE IF NOT EXISTS admin_api_keys (
  id           uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  name         text        NOT NULL,
  key_prefix   text        NOT NULL,
  key_hash     text        NOT NULL UNIQUE,
  is_active    boolean     NOT NULL DEFAULT true,
  created_at   timestamptz NOT NULL DEFAULT now(),
  last_used_at timestamptz
);
ALTER TABLE admin_api_keys ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "api_keys_admin_only" ON admin_api_keys;
CREATE POLICY "api_keys_admin_only" ON admin_api_keys FOR ALL
  USING (EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND is_admin = true));

ENDSQL
echo "--- SQL ready ---"

